(function (global) {
  function embedDashboard(options) {
    var mountPoint = options.mountPoint;
    var token = options.token;
    var supersetDomain = options.supersetDomain;
    var id = options.id;
    var width = options.width || "100%";
    var height = options.height || "100%";

    mountPoint.innerHTML = "";
    mountPoint.style.width = width;
    mountPoint.style.height = height;
    mountPoint.style.border = "0";

    var iframe = document.createElement("iframe");
    iframe.src = supersetDomain + "/embedded/" + id + "?token=" + token;
    iframe.style.width = "100%";
    iframe.style.height = "100%";
    iframe.style.border = "0";
    iframe.allow = "fullscreen";

    mountPoint.appendChild(iframe);
  }

  global.SupersetEmbeddedSdk = {
    embedDashboard: embedDashboard
  };

})(typeof self !== "undefined" ? self : this);
